This question is not currently easy to answer, unless you visit this config file, which is manually curated afaik. https://github.com/HumanCellAtlas/dcp/blob/staging/components.yml

Recently, Green box added a [/version endpoint](http://pipelines.dev.data.humancellatlas.org/version) to Lira so we can see the version of all its dependencies quickly when we are in each deployment. 

`{
  "cromwell_tools_version": "0.3.1",
  "launch_time": "2018-04-24 20:27:52 +00:00",
  "lira_version": "v0.9.1",
  "run_mode": "live_run",
  "submit_wdl_version": "v0.16.0",
  "workflow_info": {
    "Adapter10xCount": {
      "subscription_id": "placeholder-10x",
      "version": "10x_v0.1.0"
    },
    "AdapterSmartSeq2SingleCell": {
      "subscription_id": "placeholder-ss2",
      "version": "smartseq2_v0.4.0"
    }
  }
}`

A quick way to answer the question at hand could be to add a /version endpoint to the DCP CLI so we can see all the versions that are deployed in that environment.

`import kubernetes.client

from rest_apis.models import Port
from rest_apis.utils.rest_apis_utils import prune_username


class Deployment(kubernetes.client.ExtensionsV1beta1Deployment):

    def __init__(self, collection=None):
        self.collection = collection
        super(Deployment, self).__init__(api_version="extensions/v1beta1",
                                         kind="Deployment",
                                         metadata=Metadata(collection),
                                         spec=Spec(collection),
                                         status=Status()
                                         )

    def needs_service(self):
        for container in self.collection.container.all():
            if Port.objects.filter(container=container).exists():
                return True
        return False


class Metadata(kubernetes.client.V1ObjectMeta):

    def __init__(self, collection):
        super().__init__(name=collection.name,
                         namespace=get_namespace(collection),
                         labels={"app": collection.name}
                         )


class Spec(kubernetes.client.ExtensionsV1beta1DeploymentSpec):

    def __init__(self, collection):
        super().__init__(replicas=0,
                         selector=Selector(collection),
                         template=Template(collection),
                         strategy=Strategy(),
                         revision_history_limit=10
                         )


class Strategy(kubernetes.client.ExtensionsV1beta1DeploymentStrategy):

    def __init__(self):
        super().__init__(rolling_update=RollingUpdate(), type="RollingUpdate")


class RollingUpdate(kubernetes.client.ExtensionsV1beta1RollingUpdateDeployment):

    def __init__(self):
        super().__init__(max_surge="1%", max_unavailable="1%")


class Selector(kubernetes.client.V1LabelSelector):

    def __init__(self, collection):
        super().__init__(match_labels={"app": collection.name})


class Template(kubernetes.client.V1PodTemplateSpec):

    def __init__(self, collection):
        super().__init__(metadata=Metadata(collection), spec=TemplateSpec(collection))


class TemplateSpec(kubernetes.client.V1PodSpec):

    def __init__(self, collection):
        super().__init__(containers=[Containers(container) for container in collection.container.all()],
                         init_containers=self.get_init_container(collection),
                         restart_policy="Always",
                         termination_grace_period_seconds=0,
                         dns_policy="ClusterFirst",
                         volumes=[Volume(container) for container in collection.container.all()]
                         )

    @staticmethod
    def get_init_container(collection):
        env = kubernetes.client.V1EnvVar(name=collection.user.username,
                                         value=str(collection.pk))
        volume_mount = kubernetes.client.V1VolumeMount(name="data",
                                                       mount_path="/data")
        init_container = kubernetes.client.V1Container(name="s3pull",
                                                       image="registry2.swarm.devfactory.com/devfactory/wsinit",
                                                       env=[env],
                                                       volume_mounts=[volume_mount],
                                                       image_pull_policy="Always"
                                                       )
        return init_container


class Volume(kubernetes.client.V1Volume):

    def __init__(self, container):
        super().__init__(name=container.name, host_path=HostPath(container))


class HostPath(kubernetes.client.V1HostPathVolumeSource):

    def __init__(self, container):
        # super().__init__(path=container.path, type="DirectoryOrCreate")
        super().__init__(path=container.path)


class Containers(kubernetes.client.V1Container):

    def __init__(self, container):
        super().__init__(name=container.name,
                         image=container.image.devspace_url,
                         command=[command.to_json() for command in container.command.all()],
                         args=[args.to_json() for args in container.args.all()],
                         ports=[Ports(port) for port in container.port.all()],
                         volume_mounts=[VolumeMounts(container)],
                         env=[Env(env) for env in container.image.env.all()],
                         resources=Resources(),
                         termination_message_path="/dev/termination-log",
                         image_pull_policy="Always"
                         )


class Ports(kubernetes.client.V1ContainerPort):

    def __init__(self, port_obj):
        super().__init__(container_port=port_obj.port,
                         protocol=port_obj.protocol,
                         name=str(port_obj.port)
                         )


class Env(kubernetes.client.V1EnvVar):

    def __init__(self, env_object):
        super().__init__(name=env_object.name,
                         value=env_object.value
                         )


class VolumeMounts(kubernetes.client.V1VolumeMount):

    def __init__(self, container):
        super().__init__(mount_path=container.path,
                         name=container.name
                         )


class Resources(kubernetes.client.V1ResourceRequirements):

    def __init__(self):
        super().__init__({"memory": "64000Mi", "cpu": "8000m"},
                         {"memory": "100Mi", "cpu": "50m"}
                         )


class Status(kubernetes.client.ExtensionsV1beta1DeploymentStatus):

    def __init__(self):
        super().__init__()


def get_namespace(collection=None, user=None):
    if collection:
        username = prune_username(collection.user)
    else:
        username = prune_username(user)
    return "workspace-" + username`

